{
  "mode": "Indexed",
  "policyRule": {
    "if": {
      "allOf": [
        {
          "field": "[concat('tags[', parameters('tagName'), ']')]",
          "exists": "false"
        },
        {
          "value": "[resourceGroup().tags[parameters('tagName')]]",
          "notEquals": ""
        }
      ]
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "operations": [
          {
            "operation": "addOrReplace",
            "field": "[concat('tags[', parameters('tagName'), ']')]",
            "value": "[resourceGroup().tags[parameters('tagName')]]"
          }
        ]
      }
    }
  },
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": {
        "displayName": "Tag Name",
        "description": "Name of the tag to inherit from resource group"
      }
    }
  }
}

# AWS provider - default_tags apply to every resource automatically
provider "aws" {
  region = "us-east-1"
  default_tags {
    tags = {
      cost-center = var.cost_center
      environment = var.environment
      team        = var.team
      managed-by  = "terraform"
    }
  }
}

# GCP provider - labels on the project level
resource "google_project" "main" {
  project_id = "my-project"
  name       = "My Project"
  labels = {
    cost-center = var.cost_center
    environment = var.environment
    team        = var.team
    managed-by  = "terraform"
  }
}

# Azure provider - use azurerm_resource_group tags + policy for inheritance
resource "azurerm_resource_group" "main" {
  name     = "rg-${var.environment}"
  location = var.location
  tags = {
    cost-center = var.cost_center
    environment = var.environment
    team        = var.team
    managed-by  = "terraform"
  }
}

# Create a cost monitor grouped by cost-center tag
aws ce create-anomaly-monitor \
  --anomaly-monitor '{
    "MonitorName": "CostCenter-Monitor",
    "MonitorType": "DIMENSIONAL",
    "MonitorDimension": "SERVICE"
  }'

# Create an alert subscription (notify when anomaly > $100)
aws ce create-anomaly-subscription \
  --anomaly-subscription '{
    "SubscriptionName": "CostCenter-Alerts",
    "MonitorArnList": ["arn:aws:ce::123456789:anomalymonitor/monitor-id"],
    "Subscribers": [
      {"Address": "finops-alerts@company.com", "Type": "EMAIL"},
      {"Address": "arn:aws:sns:us-east-1:123456789:cost-alerts", "Type": "SNS"}
    ],
    "Threshold": 100.0,
    "Frequency": "DAILY"
  }'
